from flask import Flask, request, send_from_directory, jsonify
import os
from pathlib import Path

app = Flask(__name__)

# Server-side mapping from file IDs to stored file paths
file_mapping = {}

def normalize_path(base_dir, user_path):
    full_path = (Path(base_dir) / user_path).resolve()
    if not full_path.parent == Path(base_dir).resolve():
        return None
    return str(full_path)

@app.route('/list', methods=['GET'])
def list_directory():
    base_dir = '/uploads'
    user_path = request.args.get('path')
    normalized_path = normalize_path(base_dir, user_path)
    if not normalized_path:
        return jsonify({'error': 'Path traversal detected'}), 400
    files = os.listdir(normalized_path)
    return jsonify(files)

@app.route('/download', methods=['GET'])
def download_file():
    base_dir = '/uploads'
    file_id = request.args.get('file_id')
    if not file_id in file_mapping:
        return jsonify({'error': 'File not found'}), 404
    user_path = os.path.join(base_dir, file_mapping[file_id])
    return send_from_directory(os.path.dirname(user_path), os.path.basename(user_path))

@app.route('/info', methods=['GET'])
def get_file_info():
    base_dir = '/uploads'
    user_path = request.args.get('path')
    normalized_path = normalize_path(base_dir, user_path)
    if not normalized_path:
        return jsonify({'error': 'Path traversal detected'}), 400
    file_size = os.path.getsize(normalized_path)
    return jsonify({'size': file_size})

if __name__ == '__main__':
    app.run(debug=True)

