    # Store the uploaded file in /uploads directory
    with open(os.path.join(upload_dir, user_filename), 'wb') as f:
        f.write(request.data)
    file_mapping[len(file_mapping)] = user_filename
    return jsonify({'file_id': len(file_mapping) - 1})